245:     JodaBeanUtils.notNull(expiryZone, "expiryZone");
246:     JodaBeanUtils.notNull(underlying, "underlying");
247:     this.longShort = longShort;
248:     this.expiryDate = expiryDate;
249:     this.expiryTime = expiryTime;
250:     this.expiryZone = expiryZone;
251:     this.underlying = underlying;
252:     validate();
253:   }
