35: /**
36:  * FX (European) single barrier option.
37:  * <p>
38:  * An FX option is a financial instrument that provides an option to exchange two currencies at a specified future time
39:  * only when barrier event occurs (knock-in option) or does not occur (knock-out option).
40:  * <p>
41:  * Depending on the barrier defined in {@link Barrier}, the options are classified into four types: up-and-in,
42:  * down-and-in, up-and-out and down-and-out.
43:  * <p>
44:  * For example, an up-and-out call on a 'EUR 1.00 / USD -1.41' exchange with barrier of 1.5 is the option to
45:  * perform a foreign exchange on the expiry date, where USD 1.41 is paid to receive EUR 1.00, only when EUR/USD rate does
46:  * not exceed 1.5 during the barrier event observation period.
47:  * <p>
48:  * In case of the occurrence (non-occurrence for knock-in options) of the barrier event, the option becomes worthless,
49:  * or alternatively, a rebate is made.
50:  */
51: @BeanDefinition
52: public final class FxSingleBarrierOption
53:     implements FxOptionProduct, Resolvable<ResolvedFxSingleBarrierOption>, ImmutableBean, Serializable {
54: 
55:   /**
56:    * The underlying FX vanilla option.
57:    */
58:   @PropertyDefinition(validate = "notNull")
59:   private final FxVanillaOption underlyingOption;
60:   /**
61:    * The barrier description.
62:    * <p>
63:    * The barrier level stored in this field must be represented based on the direction of the currency pair in the
64:    * underlying FX transaction.
65:    * <p>
66:    * For example, if the underlying option is an option on EUR/GBP, the barrier should be a certain level of EUR/GBP rate.
67:    */
68:   @PropertyDefinition(validate = "notNull")
69:   private final Barrier barrier;
70:   /**
71:    * For a 'out' option, the amount is paid when the barrier is reached;
72:    * for a 'in' option, the amount is paid at expiry if the barrier is not reached.
73:    * <p>
74:    * This is the notional amount represented in one of the currency pair.
75:    * The amount should be positive.
76:    */
77:   @PropertyDefinition(get = "optional")
78:   private final CurrencyAmount rebate;
