32: /**
33:  * Perform calculations on an FX vanilla option trade for each of a set of scenarios.
34:  * <p>
35:  * This uses Black FX option volatilities, which must be specified using {@link FxOptionMarketDataLookup}.
36:  * An instance of {@link RatesMarketDataLookup} must also be specified.
37:  * <p>
38:  * Two pricing methods are available, 'Black' and 'VannaVolga'.
39:  * By default, 'Black' will be used. To control the method, pass an instance of
40:  * {@link FxVanillaOptionMethod} in the calculation parameters.
41:  * <p>
42:  * The supported built-in measures are:
43:  * <ul>
44:  *   <li>{@linkplain Measures#PRESENT_VALUE Present value}
45:  *   <li>{@linkplain Measures#PV01_CALIBRATED_SUM PV01 calibrated sum on rate curves}
46:  *   <li>{@linkplain Measures#PV01_CALIBRATED_BUCKETED PV01 calibrated bucketed on rate curves}
47:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_SUM PV01 market quote sum on rate curves}
48:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_BUCKETED PV01 market quote bucketed on rate curves}
49:  *   <li>{@linkplain Measures#CURRENCY_EXPOSURE Currency exposure}
50:  *   <li>{@linkplain Measures#CURRENT_CASH Current cash}
51:  *   <li>{@linkplain Measures#VEGA_MARKET_QUOTE_BUCKETED Vega market quote bucketed on volatility curves/surfaces}
52:  *   <li>{@linkplain Measures#RESOLVED_TARGET Resolved trade}
53:  * </ul>
54:  * <p>
55:  * The "natural" currency is the market convention base currency of the underlying FX.
56:  */
57: public class FxVanillaOptionTradeCalculationFunction
58:     implements CalculationFunction<FxVanillaOptionTrade> {
59: 
60:   /**
61:    * The calculations by measure.
62:    */
63:   private static final ImmutableMap<Measure, SingleMeasureCalculation> CALCULATORS =
64:       ImmutableMap.<Measure, SingleMeasureCalculation>builder()
65:           .put(Measures.PRESENT_VALUE, FxVanillaOptionMeasureCalculations.DEFAULT::presentValue)
66:           .put(Measures.PV01_CALIBRATED_SUM, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesCalibratedSum)
67:           .put(Measures.PV01_CALIBRATED_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesCalibratedBucketed)
68:           .put(Measures.PV01_MARKET_QUOTE_SUM, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesMarketQuoteSum)
69:           .put(Measures.PV01_MARKET_QUOTE_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::pv01RatesMarketQuoteBucketed)
70:           .put(Measures.CURRENCY_EXPOSURE, FxVanillaOptionMeasureCalculations.DEFAULT::currencyExposure)
71:           .put(Measures.OPTION_DELTA, FxVanillaOptionMeasureCalculations.DEFAULT::delta)
72:           .put(Measures.CURRENT_CASH, FxVanillaOptionMeasureCalculations.DEFAULT::currentCash)
73:           .put(Measures.VEGA_MARKET_QUOTE_BUCKETED, FxVanillaOptionMeasureCalculations.DEFAULT::vegaMarketQuoteBucketed)
74:           .put(Measures.RESOLVED_TARGET, (rt, smd, m, meth) -> rt)
75:           .build();
76: 
77:   private static final ImmutableSet<Measure> MEASURES = CALCULATORS.keySet();
78: 
79:   /**
80:    * Creates an instance.
81:    */
82:   public FxVanillaOptionTradeCalculationFunction() {
83:   }
84: 
85:   //-------------------------------------------------------------------------
86:   @Override
87:   public Class<FxVanillaOptionTrade> targetType() {
88:     return FxVanillaOptionTrade.class;
89:   }
90: 
91:   @Override
92:   public Set<Measure> supportedMeasures() {
93:     return MEASURES;
94:   }
95: 
96:   @Override
97:   public Optional<String> identifier(FxVanillaOptionTrade target) {
98:     return target.getInfo().getId().map(id -> id.toString());
99:   }
